mapper.select:
SELECT uf.document_user_id as userId, COALESCE(MAX(ui.user_name), '匿名') as userName, COALESCE(MAX(ui.photo), '') as avatar, COALESCE(SUM( CASE WHEN uf.read_stat = 1 THEN 1 ELSE 0 END + CASE WHEN uf.praise_stat = 1 THEN 2 ELSE 0 END + CASE WHEN uf.comment_stat = 1 THEN 3 ELSE 0 END + CASE WHEN uf.collection_stat = 1 THEN 2 ELSE 0 END ), 0) as count FROM user_foot uf LEFT JOIN user_info ui ON uf.document_user_id = ui.user_id AND ui.deleted = 0 WHERE uf.document_user_id > 0
AND uf.create_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY)
AND uf.document_type = 1 GROUP BY uf.document_user_id ORDER BY count DESC LIMIT #{limit}
